import SectionHeader from './SectionHeader';

const skills = [
  { icon: '🔐', name: 'Cybersecurity' },
  { icon: '🎮', name: 'Game Modding' },
  { icon: '🤖', name: 'AI & Prompt Engineering' },
  { icon: '📊', name: 'Data Analytics' },
  { icon: '📣', name: 'Digital Marketing' },
];

export default function About() {
  return (
    <section id="about" className="py-24 px-[5%] bg-cream">
      <SectionHeader tag="About Me" title='Who I <em class="italic text-teal not-italic font-serif-display">Am</em>' />
      <div className="grid md:grid-cols-2 gap-16 items-start">
        <div className="reveal space-y-8">
          <p className="text-[1.05rem] leading-[1.95] text-muted2">
            4th-year <strong className="text-ink2 font-semibold">MIS student</strong> at Sadat Academy,
            graduating 2026. I'm drawn to <strong className="text-ink2 font-semibold">Cybersecurity</strong> and{' '}
            <strong className="text-ink2 font-semibold">Game Modding</strong> — two fields that teach
            the same thing: understand the system deeply, then push its limits.
          </p>
          <div className="inline-flex items-center gap-2 bg-amber/10 border border-amber/20 px-4 py-2 rounded-full text-xs font-semibold text-amber2">
            🏅 National Scout Excellence Champion — 1st Place (2020)
          </div>
        </div>

        <div className="reveal delay-2 flex flex-col gap-2.5">
          {skills.map(s => (
            <div key={s.name}
              className="flex items-center gap-3 px-4 py-3 bg-parchment rounded-xl border-[1.5px] border-transparent shadow-sm transition-all duration-200 hover:border-amber/30 hover:translate-x-1.5 hover:shadow-md cursor-default">
              <span className="text-lg">{s.icon}</span>
              <span className="text-sm font-medium text-ink2">{s.name}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
